#include <vector>
#include <algorithm>

int maxScore(std::vector<int>& nums, int k) {
    int n = nums.size();
    int maxScore = 0;
    for (int i = 0; i < n; i++) {
        int gcd = nums[i];
        for (int j = i; j < n; j++) {
            gcd = std::gcd(gcd, nums[j]);
            int score = (j - i + 1) * gcd;
            if (k > 0 && gcd < nums[j]) {
                int idx = std::distance(nums.begin(), std::find(nums.begin() + i, nums.begin() + j + 1, nums[j]));
                nums[idx] *= 2;
                k--;
            }
            maxScore = std::max(maxScore, score);
        }
    }
    return maxScore;
}
